   318→// ─── Intent classifier ────────────────────────────────────────────────────────
   319→
   320→function classify(message) {
   321→  const m = message.toLowerCase();
   322→  if (/overdue/.test(m))                                      return 'overdue';
   323→  if (/budget/.test(m))                                       return 'budget';
   324→  if (/project/.test(m))                                      return 'projects';
   325→  if (/invoice|invoices|payment|payments|cash/.test(m))       return 'invoices';
   326→  if (/safety|incident|hazard|near.?miss|accident/.test(m))   return 'safety';
   327→  if (/team|worker|staff|member|employee/.test(m))            return 'team';
   328→  if (/\brfi\b|rfis/.test(m))                                 return 'rfis';
   329→  if (/tender|bid|bidding|pipeline/.test(m))                  return 'tenders';
   330→  return 'unknown';
   331→}
