   337→
   338→  if (!message || typeof message !== 'string' || !message.trim()) {
   339→    return res.status(400).json({ message: 'message is required' });
   340→  }
   341→
   342→  try {
   343→    const intent = classify(message.trim());
   344→    let result;
   345→
   346→    switch (intent) {
   347→      case 'projects':  result = await handleProjects();          break;
   348→      case 'invoices':  result = await handleInvoices();          break;
   349→      case 'overdue':   result = await handleOverdue();           break;
   350→      case 'safety':    result = await handleSafety();            break;
   351→      case 'team':      result = await handleTeam();              break;
   352→      case 'rfis':      result = await handleRfis();              break;
   353→      case 'tenders':   result = await handleTenders();           break;
   354→      case 'budget':    result = await handleBudget();            break;
   355→      default:          result = handleUnknown(message.trim());   break;
   356→    }
   357→
   358→    res.json({
