   771→// ─── Intent classifier ────────────────────────────────────────────────────────
   772→
   773→function classify(message) {
   774→  const m = message.toLowerCase();
   775→  if (/overdue/.test(m))                                                                        return 'overdue';
   776→  if (/budget/.test(m))                                                                         return 'budget';
   777→  if (/\brams\b|\bram\b|method statement|risk assessment/.test(m))                             return 'rams';
   778→  if (/\bcis\b|cis return|cis returns|construction industry scheme|deduction/.test(m))         return 'cis';
   779→  if (/daily report|daily reports|site diary|progress report/.test(m))                         return 'daily_reports';
   780→  if (/risk register|hazard register|\brisk\b|\brisks\b/.test(m))                              return 'risk';
   781→  if (/change order|change orders|variation|variations|\bco\b|\bvo\b/.test(m))                 return 'change_orders';
   782→  if (/purchase order|purchase orders|\bprocurement\b|supplier order/.test(m))                 return 'purchase_orders';
   783→  if (/\bpo\b/.test(m))                                                                         return 'purchase_orders';
   784→  if (/subcontractor|subcontractors|subbies|\bcontractor\b|sub-contractor/.test(m))            return 'subcontractors';
   785→  if (/\bequipment\b|\bplant\b|machinery|\bcrane\b|excavator|\bvehicle\b|\bhire\b/.test(m))    return 'equipment';
   786→  if (/\bmaterial\b|\bmaterials\b|\bsupplies\b|\bdelivery\b|\bstock\b/.test(m))                return 'materials';
   787→  if (/timesheet|timesheets|\bhours\b|\bpayroll\b|overtime/.test(m))                           return 'timesheets';
   788→  if (/\bcontact\b|\bcontacts\b|\bclient\b|\bclients\b|\bcrm\b|prospect/.test(m))              return 'contacts';
   789→  if (/project/.test(m))                                                                        return 'projects';
   790→  if (/invoice|invoices|payment|payments|cash/.test(m))                                        return 'invoices';
   791→  if (/safety|incident|hazard|near.?miss|accident/.test(m))                                    return 'safety';
   792→  if (/team|worker|staff|member|employee/.test(m))                                             return 'team';
   793→  if (/\brfi\b|rfis/.test(m))                                                                   return 'rfis';
   794→  if (/tender|bid|bidding|pipeline/.test(m))                                                   return 'tenders';
   795→  return 'unknown';
   796→}
